/**
 * Look up default pricing for a model_id.
 * Extracts the last segment after "/" and finds the template entry
 * whose model_id is the longest substring match.
 * Returns a pricing JSON string (without model_id/display_name) or null.
 */
export function lookupDefaultPricing(modelId: string): string | null {
  const segment = modelId.includes("/") ? modelId.slice(modelId.lastIndexOf("/") + 1) : modelId;
  const lower = segment.toLowerCase();

  let best: PricingTemplate | null = null;
  let bestLen = 0;
  for (const tpl of PRICING_TEMPLATES) {
    const tid = tpl.model_id.toLowerCase();
    if (lower.includes(tid) && tid.length > bestLen) {
      best = tpl;
      bestLen = tid.length;
    }
  }

  if (!best) return null;

  // Build output without model_id
  const out: Record<string, unknown> = {};
  if (best.price_each_call != null) out.price_each_call = best.price_each_call;
  if (best.price_tiers) out.price_tiers = best.price_tiers;
  if (best.flex_price_each_call != null) out.flex_price_each_call = best.flex_price_each_call;
  if (best.flex_price_tiers) out.flex_price_tiers = best.flex_price_tiers;
  if (best.scale_price_each_call != null) out.scale_price_each_call = best.scale_price_each_call;
  if (best.scale_price_tiers) out.scale_price_tiers = best.scale_price_tiers;
  if (best.priority_price_each_call != null) out.priority_price_each_call = best.priority_price_each_call;
  if (best.priority_price_tiers) out.priority_price_tiers = best.priority_price_tiers;
  return JSON.stringify(out, null, 2);
}
